record.field:
if (bom := (custom_bom := record.x_bom_id)):
    # if it's not already done: immediately create a copy for this SOL
    if bom.x_original_sol_id.id != record.id:        
        custom_bom = env.ref('construction_developer.action_duplicate_bom').with_context(bom=bom, bom_sol=record).run()

    action = {'type': 'ir.actions.act_window', 'name': f'Configure Order BOM: {custom_bom.code}', 'view_mode': 'form', 'target': 'new',
              'res_model': 'mrp.bom', 'res_id': custom_bom.id}
